#include <iostream>

using namespace std;

int add(int a, int b)
{
    return a + b;
}

int main()
{
    cout << "Before call" << endl;
    int result = add(5, 3);
    cout << "After call: " << result << endl;

    return 0;
}

int square(int n)
{
    return n * n;
}

int sumOfSquares(int a, int b)
{
    return square(a) + square(b); // one function calling another
}

void greet()
{
    cout << "Hello!" << endl;
}

int main()
{
    greet(); // called for its action, not for a value

    return 0;
}

int x = 5;
int y = 3;

add(x + 1, y * 2); // (5 + 1) and (3 * 2) are computed FIRST, then add(6, 6) runs

